// ─────────────────────────────────────────────
//  Component: Navbar
//  Fixed navigation with scroll shrink effect
// ─────────────────────────────────────────────

import React, { useEffect, useState } from 'react';
import { NAV_LINKS } from '../data/content';
import '../styles/navbar.css';

function Navbar() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 80);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`pt-navbar${scrolled ? ' scrolled' : ''}`}>
      {/* Logo */}
      <div className="pt-navbar__logo">
        PENTA<span>TECH</span>
      </div>

      {/* Links */}
      <ul className="pt-navbar__links">
        {NAV_LINKS.map(link => (
          <li key={link.label}>
            <a href={link.href}>{link.label}</a>
          </li>
        ))}
        <li>
          <a href="#contact" className="pt-navbar__cta">
            Get Started
          </a>
        </li>
      </ul>

      {/* Mobile hamburger (visual only — extend with state for full menu) */}
      <button className="pt-navbar__hamburger" aria-label="Open menu">
        <span />
        <span />
        <span />
      </button>
    </nav>
  );
}

export default Navbar;
